// Parse la sortie de daily-npm-report.py
// Le script imprime le JSON du rapport sur stdout après les logs stderr
const stdout = $input.item.json.stdout || '';
const exitCode = $input.item.json.exitCode ?? 0;

// Extraire le JSON du rapport (dernière ligne JSON valide dans stdout)
let report = null;
const lines = stdout.split('\n').filter(l => l.trim());
for (let i = lines.length - 1; i >= 0; i--) {
  try {
    const parsed = JSON.parse(lines[i]);
    if (parsed && typeof parsed === 'object' && parsed.date) {
      report = parsed;
      break;
    }
  } catch (_) {}
}

// Tenter de lire /tmp/npm-today.json si le parse stdout échoue
if (!report) {
  try {
    // Cherche un bloc JSON multi-ligne dans stdout
    const jsonMatch = stdout.match(/{[\s\S]*"date"[\s\S]*}/);
    if (jsonMatch) report = JSON.parse(jsonMatch[0]);
  } catch (_) {}
}

// Rapport vide par défaut
if (!report) {
  report = {
    date: new Date().toISOString().slice(0, 10),
    generated_at: new Date().toISOString(),
    window_hours: 24,
    top_talkers: [],
    rtt_p95_ms: null,
    art_http_p95_ms: null,
    dns_p95_ms: null,
    total_bytes: 0,
    bytes_variation_pct: null,
    perf_alerts: { total: 0, critical: 0, high: 0, medium: 0 }
  };
}

// Formatage date DD/MM/YYYY
const [year, month, day] = report.date.split('-');
const dateFR = `${day}/${month}/${year}`;

// Top talker
const topTalker = (report.top_talkers || [])[0] || null;
const topTalkerIP = topTalker ? topTalker.ip : 'N/A';
const topTalkerBytes = topTalker ? topTalker.bytes : 0;

// Formater les bytes en GB/MB
function fmtBytes(b) {
  if (!b || b === 0) return '0 B';
  if (b >= 1e9) return `${(b / 1e9).toFixed(2)} GB`;
  if (b >= 1e6) return `${(b / 1e6).toFixed(1)} MB`;
  if (b >= 1e3) return `${(b / 1e3).toFixed(1)} KB`;
  return `${b} B`;
}

// Icône statut RTT
function rttStatus(ms) {
  if (ms === null || ms === undefined) return 'N/A';
  if (ms > 300) return `${Math.round(ms)}ms [✗]`;
  if (ms > 150) return `${Math.round(ms)}ms [⚠]`;
  return `${Math.round(ms)}ms [✓]`;
}

// Icône statut ART
function artStatus(ms) {
  if (ms === null || ms === undefined) return 'N/A';
  if (ms > 500) return `${Math.round(ms)}ms [⚠]`;
  return `${Math.round(ms)}ms [✓]`;
}

// Alertes perf
const pa = report.perf_alerts || {};
const alertTotal = pa.total || 0;
const alertCrit = pa.critical || 0;
const alertHigh = pa.high || 0;

console.log(`[npm-daily] exitCode=${exitCode} | date=${report.date} | alertes=${alertTotal}`);

return [{
  json: {
    report,
    dateFR,
    topTalkerIP,
    topTalkerBytesStr: fmtBytes(topTalkerBytes),
    rttStr: rttStatus(report.rtt_p95_ms),
    artStr: artStatus(report.art_http_p95_ms),
    alertTotal,
    alertCrit,
    alertHigh,
    exitCode,
    hasErrors: exitCode !== 0
  }
}];

// Construire la Teams Adaptive Card résumé NPM
const {
  report, dateFR,
  topTalkerIP, topTalkerBytesStr,
  rttStr, artStr,
  alertTotal, alertCrit, alertHigh
} = $input.item.json;

const pa = report.perf_alerts || {};
const alertColor = alertCrit > 0 ? 'Attention' : alertHigh > 0 ? 'Warning' : 'Good';
const titleColor = alertCrit > 0 ? 'Attention' : 'Default';

// Variation J-1
let varStr = 'N/A';
if (report.bytes_variation_pct !== null && report.bytes_variation_pct !== undefined) {
  const sign = report.bytes_variation_pct >= 0 ? '+' : '';
  varStr = `${sign}${report.bytes_variation_pct.toFixed(1)}% vs J-1`;
}

// DNS p95
const dnsStr = report.dns_p95_ms !== null && report.dns_p95_ms !== undefined
  ? `${Math.round(report.dns_p95_ms)}ms`
  : 'N/A';

// Top talkers list (top 3)
const talkers = (report.top_talkers || []).slice(0, 3);
function fmtBytes(b) {
  if (!b) return '0 B';
  if (b >= 1e9) return `${(b / 1e9).toFixed(2)} GB`;
  if (b >= 1e6) return `${(b / 1e6).toFixed(1)} MB`;
  return `${(b / 1e3).toFixed(1)} KB`;
}
const talkerFacts = talkers.length > 0
  ? talkers.map((t, i) => ({ title: `#${i + 1}`, value: `${t.ip} — ${fmtBytes(t.bytes)}` }))
  : [{ title: 'Top talkers', value: 'Aucune donnée' }];

const payload = {
  type: 'message',
  attachments: [
    {
      contentType: 'application/vnd.microsoft.card.adaptive',
      content: {
        '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
        type: 'AdaptiveCard',
        version: '1.4',
        body: [
          {
            type: 'TextBlock',
            text: `📊 Rapport NPM — ${dateFR}`,
            weight: 'Bolder',
            size: 'Large',
            color: titleColor,
            wrap: true
          },
          {
            type: 'FactSet',
            facts: [
              { title: 'Top talker', value: `${topTalkerIP} (${topTalkerBytesStr})` },
              { title: 'Volume total', value: `${fmtBytes(report.total_bytes || 0)} ${varStr !== 'N/A' ? '(' + varStr + ')' : ''}`.trim() },
              { title: 'RTT p95', value: rttStr },
              { title: 'ART HTTP p95', value: artStr },
              { title: 'DNS p95', value: dnsStr },
              {
                title: 'Alertes perf',
                value: `${alertTotal} (${alertCrit} critical, ${alertHigh} high, ${pa.medium || 0} medium)`
              }
            ]
          },
          {
            type: 'TextBlock',
            text: 'Top 3 talkers (24h)',
            weight: 'Bolder',
            size: 'Small',
            separator: true
          },
          {
            type: 'FactSet',
            facts: talkerFacts
          }
        ],
        actions: [
          {
            type: 'Action.OpenUrl',
            title: 'Ouvrir NetWatch',
            url: 'http://localhost:5050'
          }
        ]
      }
    }
  ]
};

return [{ json: payload }];
